#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

/* == EXEMPLE =======================================
 * Rediriger stderr vers un pipe avec dup2
 * dup2(fd[1], STDERR_FILENO) fait que fprintf(stderr)
 * ecrit dans le pipe au lieu de la console.
 * ================================================= */
void example_dup2_stderr(void) {
    int fd[2];
    pipe(fd);
    pid_t pid = fork();
    if (pid == 0) {
        close(fd[0]);
        dup2(fd[1], STDERR_FILENO);
        close(fd[1]);
        fprintf(stderr, "error msg");
        _exit(0);
    } else {
        close(fd[1]);
        char buf[64];
        ssize_t n = read(fd[0], buf, sizeof(buf) - 1);
        buf[n] = '\0';
        printf("Captured: %s\n", buf);
        close(fd[0]);
        wait(NULL);
    }
}
/* Resultat: Captured: error msg */

